previewCss:
.darma-loader-uiverse-red-eye-shutter {
  position: relative;
  width: 78px;
  height: 78px;
  border-radius: 50%;
  background: #ffffff;
  border: 8px solid var(--loader-color, #131a1d);
  overflow: hidden;
  box-sizing: border-box;
}
.darma-loader-uiverse-red-eye-shutter::after {
  content: "";
  position: absolute;
  left: 0;
  top: -50%;
  width: 100%;
  height: 100%;
  background: var(--loader-secondary-color, #263238);
  z-index: 5;
  border-bottom: 8px solid var(--loader-color, #131a1d);
  box-sizing: border-box;
  animation: darma-loader-uiverse-red-eye-shutter-eyeShade 3s infinite;
}
.darma-loader-uiverse-red-eye-shutter::before {
  content: "";
  position: absolute;
  left: 20px;
  bottom: 15px;
  width: 32px;
  height: 32px;
  background: #111111;
  border-radius: 50%;
  animation: darma-loader-uiverse-red-eye-shutter-eyeMove 3s infinite;
}
@keyframes darma-loader-uiverse-red-eye-shutter-eyeShade {
  0% { transform: translateY(0); }
  20% { transform: translateY(5px); }
  40%, 50% { transform: translateY(-5px); }
  60% { transform: translateY(-8px); }
  75% { transform: translateY(5px); }
  100% { transform: translateY(10px); }
}
@keyframes darma-loader-uiverse-red-eye-shutter-eyeMove {
  0% { transform: translate(0, 0); }
  20% { transform: translate(0, 5px); }
  40%, 50% { transform: translate(0, -5px); }
  60% { transform: translate(-10px, -5px); }
  75% { transform: translate(-20px, 5px); }
  100% { transform: translate(0, 10px); }
}

